    for _, edge := range edges {
        if edge[2] > max_w {
            max_w = edge[2]
        }
    }
    low := 0
    high := int64(max_w)
    answer := int64(max_w)

    for low <= high {
        mid := (low + high) / 2
        adj := make([][]int64, int(n))
        for _, edge := range edges {
            if edge[2] <= mid {
                adj[edge[0]] = append(adj[edge[0]], edge[1])
                adj[edge[1]] = append(adj[edge[1]], edge[0])
            }
        }
        visited := make([]bool, int(n))
        components := 0

        for i := 0; i < int(n); i++ {
            if !visited[i] {
                components++
                stack := []int64{i}
                visited[i] = true
                for len(stack) > 0 {
                    node := stack[len(stack)-1]
                    stack = stack[:len(stack)-1]
                    for _, neighbor := range adj[node] {
                        if !visited[neighbor] {
                            visited[neighbor] = true
                            stack = append(stack, neighbor)
                        }
                    }
                }
            }
        }

        if components <= k {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return answer
}
